async (params, browser) => {
  // Open Vivino search
  await browser.open(`https://www.vivino.com/search/wines?q=${params.query}`)

  // Wait for results
  await browser.waitForSelector('[class*="explorerCard"], [class*="wineCard"], [class*="vintageTitle"], .inner-page', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('[class*="explorerCard"], [class*="wineCard"], [class*="cleanWineCard"]').forEach((el, i) => { if (i < 15) { const nameEl = el.querySelector('[class*="vintageTitle"] a, [class*="wine"] a, a[href*="/w/"]'); const wineryEl = el.querySelector('[class*="winery"], a[href*="/wineries/"]'); const ratingEl = el.querySelector('[class*="averageValue"], [class*="averageRating"], [class*="rating"]'); const priceEl = el.querySelector('[class*="price"], [class*="amount"]'); const regionEl = el.querySelector('[class*="region"], [class*="country"], [class*="Location"]'); results.push({ name: nameEl?.textContent?.trim() || '', url: nameEl?.href || '', winery: wineryEl?.textContent?.trim() || '', rating: ratingEl?.textContent?.trim() || '', price: priceEl?.textContent?.trim() || '', region: regionEl?.textContent?.trim() || '' }); } }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return search_results
}
